base_css:
/* Base Resets */
    body {
      margin: 0;
      font-family: 'DM Sans', -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, Helvetica, Arial, sans-serif;
      background-color: var(--bg-body);
      color: var(--text);
      overflow-x: hidden;
      padding-top: var(--header-h); 
    }
    @media (max-width: 991px) { body { padding-top: 64px; } }

    a { text-decoration: none; color: var(--primary); transition: color var(--t); }
    a:hover { color: var(--primary-2); }
    p { line-height: 1.7; color: var(--text-s); font-size: 0.95rem; }

    .font-syne { font-family: 'Syne', sans-serif; }

    /* ========================================================================== */
    /* COMPONENTS & TYPOGRAPHY                                                    */
    /* ========================================================================== */
    .section-title {
      position: relative; padding-bottom: .75rem; margin-bottom: 2rem;
      font-weight: 800; color: var(--primary-d); font-family: 'Syne', sans-serif;
      font-size: clamp(1.6rem, 4vw, 2.2rem);
    }
    .section-title::after {
      content: ''; position: absolute; bottom: 0; left: 0;
      width: 60px; height: 4px; border-radius: 2px;
      background: linear-gradient(90deg, var(--primary), var(--gold));
    }
    .section-title.center::after { left: 50%; transform: translateX(-50%); }

    /* ========================================================================== */
    /* HERO SECTION                                                               */
    /* ========================================================================== */
    .hero-banner {
      position: relative; overflow: hidden;
      background: linear-gradient(135deg, var(--digital-blue-950) 0%, var(--digital-blue-900) 50%, var(--digital-blue-800) 100%);
      padding: 80px 0 100px; text-align: center;
    }
    .hero-banner::before {
      content: ''; position: absolute; inset: 0;
      background-image: 
        radial-gradient(circle at 15% 50%, rgba(51, 133, 255, 0.2), transparent 30%),
        radial-gradient(circle at 85% 30%, rgba(51, 133, 255, 0.2), transparent 30%);
      z-index: 1; pointer-events: none;
    }
    .hero-ring {
      position: absolute; border-radius: 50%; border: 1px solid rgba(255,255,255,.05);
      pointer-events: none; z-index: 1;
    }
    .hero-ring-1 { width: 600px; height: 600px; top: -200px; left: -150px; border-color: rgba(51, 133, 255, 0.15); }
    .hero-ring-2 { width: 400px; height: 400px; bottom: -100px; right: -50px; border-color: rgba(255,255,255,.05); }

    .hero-content { position: relative; z-index: 3; max-width: 800px; margin: 0 auto; }
    .hero-breadcrumb {
      display: inline-flex; align-items: center; gap: 8px;
      color: var(--gold); font-size: .75rem; font-weight: 800; text-transform: uppercase; letter-spacing: 0.08em;
      background: rgba(51, 133, 255, 0.15); border: 1px solid rgba(51, 133, 255, 0.3);
      border-radius: 50px; padding: 6px 16px; margin-bottom: 24px;
      transition: all var(--t);
    }
    .hero-breadcrumb:hover { background: rgba(51, 133, 255, 0.25); color: #fff; transform: translateY(-2px); }
    .hero-banner h1 {
      font-size: clamp(2.5rem, 5vw, 3.8rem); font-weight: 800; color: #fff; 
      letter-spacing: -.02em; margin-bottom: 16px; text-shadow: 0 4px 20px rgba(0,0,0,0.3);
    }
    .hero-banner p {
      font-size: 1.15rem; color: rgba(255,255,255,.75); line-height: 1.7; margin-bottom: 0;
    }

    /* ========================================================================== */
    /* FILTER TABS                                                                */
    /* ========================================================================== */
    .filter-tabs {
      display: flex; flex-wrap: wrap; gap: 10px; justify-content: center;
      margin-top: -30px; position: relative; z-index: 10; margin-bottom: 40px;
    }
    .filter-tab {
      padding: 12px 24px; border-radius: 50px; background: #fff; 
      border: 1px solid var(--bdr); font-weight: 700; font-size: .9rem;
      color: var(--text-m); cursor: pointer; transition: all var(--t);
      box-shadow: var(--sh-xs);
    }
    .filter-tab:hover { border-color: var(--primary-l); color: var(--primary); transform: translateY(-2px); box-shadow: var(--sh-sm); }
    .filter-tab.active { 
      background: var(--primary); color: #fff; border-color: var(--primary); 
      box-shadow: 0 6px 16px rgba(0,102,255,0.25); transform: translateY(-2px);
    }
    @media (max-width: 768px) {
      .filter-tabs { margin-top: -20px; gap: 8px; }
      .filter-tab { padding: 10px 18px; font-size: .85rem; }
    }

    /* ========================================================================== */
    /* LAB CARDS (SaaS Design)                                                    */
    /* ========================================================================== */
    .lab-grid {
      display: grid;
      grid-template-columns: repeat(3, 1fr);
      gap: 24px;
      margin-bottom: 40px;
    }
    @media(max-width:991px) { .lab-grid { grid-template-columns: repeat(2, 1fr); } }
    @media(max-width:640px) { .lab-grid { grid-template-columns: 1fr; } }

    .lab-card-wrap {
      animation: fadeInSlideUp 0.4s ease-out forwards;
    }
    @keyframes fadeInSlideUp {
      from { opacity: 0; transform: translateY(20px); }
      to { opacity: 1; transform: translateY(0); }
    }

    .lab-card {
      background: #fff;
      border-radius: 16px;
      overflow: hidden;
      border: 1px solid rgba(0,0,0,0.06);
      box-shadow: var(--sh-sm);
      transition: transform 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275), box-shadow 0.3s ease;
      cursor: pointer;
      display: flex;
      flex-direction: column;
      height: 100%;
    }
    .lab-card:hover {
      transform: translateY(-8px);
      box-shadow: 0 16px 36px rgba(0,0,0,0.08);
      border-color: rgba(51,133,255,0.15);
    }

    .lab-top {
      aspect-ratio: 21/9;
      display: flex;
      align-items: center;
      justify-content: center;
      font-size: 3.5rem; 
      background-size: cover;
      background-position: center;
      background-color: var(--sur-2);
      border-bottom: 1px solid rgba(0,0,0,0.04);
      transition: transform var(--t);
    }
    .lab-body {
      padding: 24px;
      display: flex;
      flex-direction: column;
      flex: 1;
    }

    .lab-badge {
      font-size: 0.7rem;
      font-weight: 800;
      color: var(--primary-d);
      background: var(--digital-blue-50);
      padding: 4px 12px;
      border-radius: 50px;
      text-transform: uppercase;
      letter-spacing: 0.05em;
      display: inline-block;
      margin-bottom: 14px;
      align-self: flex-start;
    }

    .lab-title {
      font-family: 'DM Sans', sans-serif;
      font-size: 1.25rem;
      font-weight: 800;
      color: var(--primary-d);
      margin-bottom: 12px;
      line-height: 1.35;
    }

    .lab-desc-preview {
      font-size: 0.9rem;
      color: var(--text-s);
      line-height: 1.6;
      margin-bottom: 20px;
      display: -webkit-box;
      -webkit-line-clamp: 2;
      -webkit-box-orient: vertical;
      overflow: hidden;
    }

    .lab-action {
      margin-top: auto;
      font-size: 0.85rem;
      color: var(--primary);
      font-weight: 700;
      display: flex;
      align-items: center;
      gap: 8px;
      border-top: 1px solid var(--bdr-s);
      padding-top: 18px;
      transition: gap 0.2s;
    }
    .lab-action i { font-size: 1.1rem; }
    .lab-card:hover .lab-action { gap: 12px; color: var(--primary-2); }

    /* ========================================================================== */
    /* SPLIT-LAYOUT MODAL                                                         */
    /* ========================================================================== */
    .lab-modal-overlay {
      display: none;
      position: fixed; inset: 0;
      background: rgba(0,14,36,0.65);
      z-index: 10000;
      align-items: center; justify-content: center;
      padding: 20px;
      backdrop-filter: blur(6px);
      -webkit-backdrop-filter: blur(6px);
    }
    .lab-modal-overlay.open { display: flex; }

    .lab-modal {
      width: 860px; max-width: 100%;
      background: #fff;
      border-radius: 24px;
      overflow: hidden;
      box-shadow: 0 24px 60px rgba(0,0,0,0.2);
      animation: modalPop 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275);
      display: flex;
      flex-direction: row;
      position: relative;
    }
    @keyframes modalPop {
      from { transform: scale(0.92); opacity: 0; }
      to { transform: scale(1); opacity: 1; }
    }

    .lab-m-top {
      width: 40%;
      min-height: 420px;
      position: relative;
      display: flex; align-items: center; justify-content: center;
      font-size: 6rem;
      background-size: cover;
      background-position: center;
      background-color: var(--primary-l);
    }
    .lab-m-top::after {
      content: ''; position: absolute; inset: 0;
      box-shadow: inset -10px 0 20px rgba(0,0,0,0.03);
      pointer-events: none;
    }

    .lab-m-body { 
      width: 60%;
      padding: 48px 40px; 
      background: #fff; 
      overflow-y: auto;
      max-height: 85vh;
      position: relative;
    }

    .lab-m-close {
      position: absolute; top: 20px; right: 20px;
      width: 36px; height: 36px; border-radius: 50%;
      background: var(--sur-2); color: var(--text-s); 
      border: 1px solid var(--bdr);
      display: flex; align-items: center; justify-content: center;
      cursor: pointer; font-size: 1.1rem; z-index: 10;
      transition: all 0.2s;
    }
    .lab-m-close:hover { background: var(--error); color: #fff; border-color: var(--error); transform: rotate(90deg); }

    .lab-m-title {
      font-size: 1.8rem; font-weight: 800; color: var(--primary-d);
      margin: 16px 0 20px 0; line-height: 1.25; font-family: 'DM Sans', sans-serif;
    }

    .lab-m-desc {
      font-size: 0.95rem; color: var(--text-s); line-height: 1.7; margin-bottom: 24px;
    }

    .lab-m-list { list-style: none; padding: 0; margin: 0; }
    .lab-m-list li {
      display: flex; align-items: flex-start; gap: 16px;
      padding: 16px 0; border-bottom: 1px solid var(--bdr-s);
    }
    .lab-m-list li:last-child { border-bottom: none; padding-bottom: 0; }

    .lab-m-icon {
      width: 44px; height: 44px; border-radius: 12px;
      background: var(--digital-blue-50); color: var(--digital-blue-600);
      display: flex; align-items: center; justify-content: center;
      font-size: 1.2rem; flex-shrink: 0; border: 1px solid rgba(0,102,255,0.05);
    }
    .lab-m-info { display: flex; flex-direction: column; gap: 4px; }
    .lab-m-label {
      font-size: 0.72rem; font-weight: 800; letter-spacing: 0.05em;
      text-transform: uppercase; color: var(--text-m);
    }
    .lab-m-val { font-size: 0.95rem; font-weight: 600; color: var(--primary-d); line-height: 1.5; }

    @media (max-width: 768px) {
      .lab-modal { flex-direction: column; width: 92%; }
      .lab-m-top { width: 100%; min-height: 200px; height: 200px; border-right: none; border-bottom: 1px solid var(--bdr-s); }
      .lab-m-top::after { display: none; }
      .lab-m-body { width: 100%; padding: 32px 24px; }
      .lab-m-close { top: 16px; right: 16px; background: rgba(255,255,255,0.9); border-color: transparent; }
      .lab-m-close:hover { background: #fff; color: var(--error); transform: none; }
      .lab-m-title { font-size: 1.5rem; }
    }

    /* ========================================================================== */
    /* ANIMATIONS (Scroll Reveal)                                                 */
    /* ========================================================================== */
    .fade-up { opacity: 0; transform: translateY(32px); transition: opacity .6s var(--ease), transform .6s var(--ease); }
    .fade-up.visible { opacity: 1; transform: translateY(0); }
    .fade-in { opacity: 0; transition: opacity .6s var(--ease); }
    .fade-in.visible { opacity: 1; }

    .delay-1 { transition-delay: .05s; }
    .delay-2 { transition-delay: .1s; }
    .delay-3 { transition-delay: .15s; }
    .delay-4 { transition-delay: .2s; }

base_js:
/* ========================================================================== */
  /* PAGE INTERACTIONS (Filters, Modals, Scroll Reveal)                         */
  /* ========================================================================== */
  (function () {
    'use strict';
fetch('https://gpnainital.com/api/data/TABLE_NAME?key=YOUR_API_KEY')
  .then(res => res.json())
  .then(data => {
    // data.data contains the database records!
    console.log(data.data);

    // Example: Render inside your component
    const container = document.getElementById('my-grid');
    data.data.forEach(row => {
      container.innerHTML += 
        <div class="card">
           <h3>+row.title+</h3>
        </div>;
    });
  });
    /* ── 1. Scroll-Reveal ── */
    const revealEls = document.querySelectorAll('.fade-up, .fade-in');
    if (revealEls.length) {
      const obs = new IntersectionObserver(
        (entries) => {
          entries.forEach((entry) => {
            if (entry.isIntersecting) {
              entry.target.classList.add('visible');
              obs.unobserve(entry.target);
            }
          });
        },
        { threshold: 0.1 }
      );
      revealEls.forEach((el) => obs.observe(el));
    }

    /* ── 2. Filter Logic ── */
    document.querySelectorAll('.filter-tab').forEach(btn => {
      btn.addEventListener('click', () => {
        document.querySelectorAll('.filter-tab').forEach(b => b.classList.remove('active'));
        btn.classList.add('active');

        const filter = btn.dataset.f;
        document.querySelectorAll('.lab-card-wrap').forEach((wrap, index) => {
          const card = wrap.querySelector('.lab-card');
          if (filter === 'all' || card.dataset.dept === filter) {
            wrap.style.display = 'block';
            wrap.style.animation = 'none';
            void wrap.offsetWidth; // Trigger reflow
            wrap.style.animation = `fadeInSlideUp 0.4s ease-out forwards`;
            wrap.style.animationDelay = `${(index % 5) * 0.05}s`;
          } else {
            wrap.style.display = 'none';
          }
        });
      });
    });

    /* ── 3. Split-Layout Modal Logic ── */
    document.querySelectorAll('.lab-card').forEach((card) => {
      card.addEventListener('click', () => {
        document.getElementById('mEmoji').textContent   = card.dataset.emoji   || '';
        document.getElementById('mTop').style.backgroundColor = card.dataset.bg || 'var(--primary-l)';

        // Copy the specific styled badge
        const badgeHTML = card.querySelector('.lab-badge').outerHTML;
        document.getElementById('mDeptTag').outerHTML = badgeHTML;
        document.querySelector('.lab-m-body .lab-badge').id = 'mDeptTag'; // Re-attach ID

        document.getElementById('mTitle').textContent   = card.dataset.title   || '';
        document.getElementById('mDesc').textContent    = card.dataset.desc    || '';
        document.getElementById('mEquip').textContent   = card.dataset.equip   || 'Standard Lab Equipment';
        document.getElementById('mCap').textContent     = card.dataset.capacity|| '30 Students';

        const software = card.dataset.software;
        if(software && software.toLowerCase() !== 'n/a' && !software.toLowerCase().includes('physical')) {
            document.getElementById('mSoft').textContent = software;
            document.getElementById('mSoftRow').style.display = 'flex';
        } else {
            document.getElementById('mSoftRow').style.display = 'none';
        }

        document.getElementById('labModalOverlay').classList.add('open');
        document.body.style.overflow = 'hidden';
      });
    });

    const overlay = document.getElementById('labModalOverlay');
    const closeBtn = document.getElementById('mClose');

    function closeLabModal() {
      overlay.classList.remove('open');
      document.body.style.overflow = '';
    }

    if(closeBtn) closeBtn.addEventListener('click', closeLabModal);
    if(overlay) overlay.addEventListener('click', e => {
      if (e.target === overlay) closeLabModal();
    });
    document.addEventListener('keydown', e => {
      if (e.key === 'Escape') closeLabModal();
    });

    // Trigger initial filter to start staggered animation
    document.querySelector('.filter-tab[data-f="all"]').click();

  })();
